const DAY_KEYS = ["mon", "tue", "wed", "thu", "fri", "sat", "sun"] as const;

export function t(lang: Lang, key: string, params?: Record<string, string | number>): string {
  const row = D[key];
  let s = row ? (row[lang] ?? row.uk) : key;
  if (params) for (const [k, v] of Object.entries(params)) s = s.replaceAll(`{${k}}`, String(v));
  return s;
}

// All language variants of a key — used as Telegraf hears() triggers so a button
// works no matter which language the worker picked.
export function trAll(key: string): string[] {
  const row = D[key];
  return row ? [...new Set(LANGS.map(l => row[l]))] : [key];
}

export const dayShort = (lang: Lang, day: string) => t(lang, `d.${day}`);
export const stageLabel = (lang: Lang, stage: string) => t(lang, `stage.${stage}`) || stage;

// Intl locale per bot language — for toLocaleDateString (localized month names etc.)
export const DATE_LOCALE: Record<Lang, string> = { uk: "uk-UA", en: "en-GB", es: "es-ES", ru: "ru-RU", pl: "pl-PL" };
export { DAY_KEYS };

// ─────────────────────────────────────────────────────────────────────────────
// Office/admin + driver bot localisation (Ukrainian + English + Russian).
// Uses the "Ukrainian-string-as-key" approach (like the web panel): the uk text
// IS the key, BOT_EN holds uk→en, BOT_RU holds uk→ru (partial — driver-facing
// strings; anything missing falls back to uk). tb(lang, uk) picks by lang.
// bhears(uk) returns every language variant so bot.hears matches any of them.
export const OFFICE_LANGS: Lang[] = ["uk", "en", "ru"];
export const oLang = (v: any): Lang => (v === "en" ? "en" : v === "ru" ? "ru" : "uk"); // office/driver: uk default

